mapper.select:
select id, tenant_id, task_type, name,
       parameters::text as parameters, created_by, created_at, updated_at
from batch.atomic_task_config
where tenant_id = #{tenantId}
  and task_type = #{taskType}
order by created_at desc, id desc

select id, tenant_id, task_type, name,
       parameters::text as parameters, created_by, created_at, updated_at
from batch.atomic_task_config
where tenant_id = #{tenantId}
  and id = #{id}

select id, tenant_id, task_type, name,
       parameters::text as parameters, created_by, created_at, updated_at
from batch.atomic_task_config
where tenant_id = #{tenantId}
  and task_type = #{taskType}
  and name = #{name}
